const MN={january:1,jan:1,february:2,feb:2,march:3,mar:3,april:4,apr:4,may:5,june:6,jun:6,july:7,jul:7,august:8,aug:8,september:9,sep:9,sept:9,october:10,oct:10,november:11,nov:11,december:12,dec:12};
const ML=["","January","February","March","April","May","June","July","August","September","October","November","December"];
const MD=[0,31,28,31,30,31,30,31,31,30,31,30,31];
function isLY(y){return(y%4===0&&y%100!==0)||y%400===0}
function dim(m,y){return m===2&&isLY(y)?29:MD[m]}
function parse(raw){
  const c=raw.toLowerCase().replace(/\b(\d+)(st|nd|rd|th)\b/g,"$1").replace(/[,]/g," ").replace(/\s+/g," ").trim();
  let m;
  m=c.match(/^([a-z]+)\s+(\d{1,2})\s+(\d{2,4})$/);
  if(m&&MN[m[1]])return{month:MN[m[1]],day:+m[2],year:+m[3],amb:false};
  const c2=c.replace(/\bof\b/g,"").replace(/\s+/g," ").trim();
  m=c2.match(/^(\d{1,2})\s+([a-z]+)\s+(\d{2,4})$/);
  if(m&&MN[m[2]])return{month:MN[m[2]],day:+m[1],year:+m[3],amb:false};
  m=c.match(/^(\d{1,2})[/\-.](\d{1,2})[/\-.](\d{2,4})$/);
  if(m){const a=+m[1],b=+m[2];return{month:a,day:b,year:+m[3],amb:a<=12&&b<=12&&a!==b}}
  m=c.match(/^(\d{4})[/\-.](\d{1,2})[/\-.](\d{1,2})$/);
  if(m)return{month:+m[2],day:+m[3],year:+m[1],amb:false};
  m=c.match(/^(\d{4})$/);
  if(m)return{month:0,day:0,year:+m[1],amb:false};
  m=c.match(/^([a-z]+)\s+(\d{4})$/);
  if(m&&MN[m[1]])return{month:MN[m[1]],day:0,year:+m[2],amb:false};
  return null;
}
const dob=dv.date_of_birth;
if(!dob||!dob.trim()){return{valid:false,error:"No date of birth provided",age:null,formatted:null,needs_clarification:false,clarification_reason:null}}
const p=parse(dob.trim());
if(!p){return{valid:false,error:"Could not understand the date of birth. Could you say it as month, day, year?",age:null,formatted:null,needs_clarification:true,clarification_reason:"format_unclear"}}
let{month,day,year,amb}=p;
if(!month||!day||!year){const ms=[];if(!month)ms.push("month");if(!day)ms.push("day");if(!year)ms.push("year");return{valid:false,error:"The date is missing the "+ms.join(" and ")+". Could you give the full date?",age:null,formatted:null,needs_clarification:true,clarification_reason:"missing_components"}}
if(year<100){const cy=new Date().getFullYear();const c21=2000+year;year=c21<=cy?c21:1900+year}
if(month<1||month>12)return{valid:false,error:"Month "+month+" is not valid.",age:null,formatted:null,needs_clarification:false,clarification_reason:null};
const mx=dim(month,year);
if(day<1||day>mx)return{valid:false,error:ML[month]+" "+year+" only has "+mx+" days, so day "+day+" doesn't exist.",age:null,formatted:null,needs_clarification:false,clarification_reason:null};
const today=new Date();today.setHours(0,0,0,0);const d=new Date(year,month-1,day);
if(d>today)return{valid:false,error:"That date is in the future.",age:null,formatted:ML[month]+" "+day+", "+year,needs_clarification:false,clarification_reason:null};
let age=today.getFullYear()-d.getFullYear();const md=today.getMonth()-d.getMonth();if(md<0||(md===0&&today.getDate()<d.getDate()))age--;
if(age>120)return{valid:false,error:"That would make the patient "+age+" years old, which seems unlikely. Could you double-check the year?",age,formatted:ML[month]+" "+day+", "+year,needs_clarification:true,clarification_reason:"age_over_120"};
if(amb)return{valid:false,error:"Just to be sure — is that "+ML[month]+" "+day+" or "+ML[day]+" "+month+"?",age,formatted:ML[month]+" "+day+", "+year,needs_clarification:true,clarification_reason:"ambiguous_month_day"};
if(age<1)return{valid:true,error:null,age:0,formatted:ML[month]+" "+day+", "+year,needs_clarification:true,clarification_reason:"infant_under_one"};
return{valid:true,error:null,age,formatted:ML[month]+" "+day+", "+year,needs_clarification:false,clarification_reason:null};
